t.t:
.breadcrumb { font-size: 12.5px; color: var(--text-muted); margin-bottom: 20px; }
.breadcrumb a { color: var(--primary); text-decoration: none; }
.breadcrumb a:hover { text-decoration: underline; }

/* Cabeçalho da oportunidade */
.opp-header {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 24px 28px;
    margin-bottom: 24px;
    display: flex;
    gap: 24px;
    align-items: flex-start;
    flex-wrap: wrap;
}
.opp-header-main { flex: 1; }
.opp-header-main h2 {
    font-family: 'Source Serif 4', serif;
    font-size: 22px; font-weight: 700;
    color: var(--primary); margin-bottom: 8px;
}
.opp-meta-row { display: flex; gap: 20px; flex-wrap: wrap; margin-top: 10px; }
.opp-meta-item { font-size: 13px; color: var(--text-muted); display: flex; align-items: center; gap: 5px; }
.opp-meta-item strong { color: var(--text-primary); }
.opp-desc { font-size: 13.5px; color: var(--text-muted); margin-top: 12px; line-height: 1.6; }
.opp-stats { display: flex; flex-direction: column; gap: 8px; min-width: 140px; }
.opp-stat-box {
    background: var(--bg-page);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 10px 16px;
    text-align: center;
}
.opp-stat-num { font-size: 26px; font-weight: 700; color: var(--primary); line-height: 1; }
.opp-stat-lbl { font-size: 11px; color: var(--text-muted); margin-top: 3px; }

/* Barra de filtros e pesquisa */
.cand-toolbar {
    display: flex; align-items: center; gap: 10px;
    margin-bottom: 16px; flex-wrap: wrap;
}
.cand-search { position: relative; flex: 1; min-width: 200px; max-width: 320px; }
.cand-search input {
    width: 100%; padding: 8px 12px 8px 34px;
    border: 1px solid var(--border); border-radius: 6px;
    font-size: 13px; font-family: inherit; outline: none; transition: border .15s;
    background: var(--bg-card);
}
.cand-search input:focus { border-color: var(--primary); }
.cand-search .si { position: absolute; left: 11px; top: 50%; transform: translateY(-50%); color: var(--text-muted); font-size: 13px; }
.stage-pills { display: flex; gap: 6px; flex-wrap: wrap; }
.spill {
    padding: 5px 14px; border-radius: 20px; font-size: 12px;
    border: 1px solid var(--border); background: var(--bg-card);
    color: var(--text-muted); cursor: pointer; font-family: inherit; transition: all .15s;
}
.spill.active, .spill:hover { background: var(--primary); color: #fff; border-color: var(--primary); }
.cand-count { font-size: 13px; color: var(--text-muted); margin-left: auto; }

/* Tabela de candidatos */
.cand-table-wrap {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 12px;
    overflow: hidden;
}
.cand-table { width: 100%; border-collapse: collapse; font-size: 13.5px; }
.cand-table th {
    text-align: left; padding: 11px 16px;
    font-size: 11px; font-weight: 700;
    text-transform: uppercase; letter-spacing: 0.06em;
    color: var(--text-muted); background: var(--bg-page);
    border-bottom: 1px solid var(--border);
}
.cand-table td { padding: 13px 16px; border-bottom: 1px solid var(--border); vertical-align: middle; }
.cand-table tr:last-child td { border-bottom: none; }
.cand-table tr { transition: background .1s; cursor: pointer; }
.cand-table tr:hover td { background: #F8FAFD; }
.cand-name { font-weight: 600; color: var(--text-primary); }
.cand-nr   { font-size: 12px; color: var(--text-muted); margin-top: 2px; }
.stage-badge {
    display: inline-flex; align-items: center; padding: 3px 10px;
    border-radius: 20px; font-size: 11.5px; font-weight: 600;
}
.stage-novo      { background: #E6F1FB; color: #0F4C81; }
.stage-analise   { background: #EEEDFE; color: #3C3489; }
.stage-aprovado  { background: #E1F5EE; color: #0F6E56; }
.stage-rejeitado { background: #FAECE7; color: #993C1D; }
.action-btn {
    padding: 5px 12px; border-radius: 6px; font-size: 12px;
    font-weight: 500; border: none; cursor: pointer;
    font-family: inherit; transition: opacity .15s; color: #fff;
}
.action-btn:hover { opacity: 0.85; }
.empty-row td { text-align: center; padding: 48px; color: var(--text-muted); font-size: 14px; }

t.script:
let activeStage = 'todos';

function setStage(el) {
    document.querySelectorAll('.spill').forEach(p => p.classList.remove('active'));
    el.classList.add('active');
    activeStage = el.dataset.stage;
    filterCandidatos();
}

function filterCandidatos() {
    const q = document.getElementById('cand-search').value.toLowerCase();
    const rows = document.querySelectorAll('#cand-tbody tr[data-stage]');
    let visible = 0;
    rows.forEach(row => {
        const stageMatch = activeStage === 'todos' || row.dataset.stage === activeStage;
        const searchMatch = !q || row.dataset.search.toLowerCase().includes(q);
        const show = stageMatch && searchMatch;
        row.style.display = show ? '' : 'none';
        if (show) visible++;
    });
    document.getElementById('cand-count').textContent = visible + ' candidato(s)';
}

function moverCandidato(leadId, stage) {
    fetch('/api/candidaturas/move', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            jsonrpc: '2.0', method: 'call', id: 1,
            params: { lead_id: leadId, target_stage: stage }
        })
    })
    .then(r => r.json())
    .then(data => {
        if (data.result && data.result.success) {
            location.reload();
        } else {
            alert('Erro: ' + (data.result ? data.result.message : 'Falha'));
        }
    });
}

t.t:
.breadcrumb { font-size: 12.5px; color: var(--text-muted); margin-bottom: 20px; }
.breadcrumb a { color: var(--primary); text-decoration: none; }
.breadcrumb a:hover { text-decoration: underline; }
.ficha-grid { display: grid; grid-template-columns: 1fr 320px; gap: 20px; align-items: start; }
@media(max-width:860px) { .ficha-grid { grid-template-columns: 1fr; } }
.ficha-card {
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: 12px; padding: 24px 28px; margin-bottom: 16px;
}
.ficha-card h3 {
    font-size: 13px; font-weight: 700; text-transform: uppercase;
    letter-spacing: 0.08em; color: var(--text-muted);
    margin-bottom: 16px; padding-bottom: 10px; border-bottom: 1px solid var(--border);
}
.ficha-avatar {
    width: 64px; height: 64px; border-radius: 50%;
    background: var(--primary); color: #fff;
    font-size: 22px; font-weight: 700;
    display: flex; align-items: center; justify-content: center;
    margin-bottom: 16px;
}
.ficha-nome { font-size: 20px; font-weight: 700; color: var(--text-primary); margin-bottom: 4px; }
.ficha-sub  { font-size: 13px; color: var(--text-muted); margin-bottom: 14px; }
.info-row { display: flex; flex-direction: column; gap: 12px; }
.info-item { display: flex; justify-content: space-between; align-items: baseline; gap: 12px; }
.info-label { font-size: 12.5px; color: var(--text-muted); flex-shrink: 0; }
.info-value { font-size: 13.5px; font-weight: 500; color: var(--text-primary); text-align: right; }
.motivacao-text {
    font-size: 13.5px; color: var(--text-primary);
    line-height: 1.7; white-space: pre-wrap;
    background: var(--bg-page); border-radius: 8px;
    padding: 14px; border: 1px solid var(--border);
}
.opp-ref-card {
    background: var(--primary-light);
    border: 1px solid #C5DCF2;
    border-radius: 10px; padding: 16px;
    margin-bottom: 16px;
}
.opp-ref-label { font-size: 11px; text-transform: uppercase; letter-spacing: 0.08em; color: var(--primary); font-weight: 700; margin-bottom: 6px; }
.opp-ref-name  { font-size: 14px; font-weight: 600; color: var(--primary); }
.opp-ref-sub   { font-size: 12px; color: #3A6A9A; margin-top: 3px; }
.estado-card {
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: 10px; padding: 16px; margin-bottom: 16px;
}
.estado-card h3 { font-size: 12px; text-transform: uppercase; letter-spacing: 0.08em; color: var(--text-muted); font-weight: 700; margin-bottom: 12px; }
.stage-badge-lg {
    display: flex; align-items: center; justify-content: center;
    padding: 10px; border-radius: 8px; font-size: 14px; font-weight: 700;
    margin-bottom: 14px;
}
.stage-novo      { background: #E6F1FB; color: #0F4C81; }
.stage-analise   { background: #EEEDFE; color: #3C3489; }
.stage-aprovado  { background: #E1F5EE; color: #0F6E56; }
.stage-rejeitado { background: #FAECE7; color: #993C1D; }
.action-stack { display: flex; flex-direction: column; gap: 8px; }
.action-full {
    width: 100%; padding: 9px; border-radius: 6px; font-size: 13px;
    font-weight: 600; border: none; cursor: pointer; font-family: inherit;
    color: #fff; transition: opacity .15s; text-align: center;
}
.action-full:hover { opacity: 0.85; }

t.script:
function mover(leadId, stage) {
    const btns = document.querySelectorAll('.action-full');
    btns.forEach(b => b.disabled = true);

    fetch('/api/candidaturas/move', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            jsonrpc: '2.0', method: 'call', id: 1,
            params: { lead_id: leadId, target_stage: stage }
        })
    })
    .then(r => r.json())
    .then(data => {
        if (data.result && data.result.success) {
            location.reload();
        } else {
            alert('Erro: ' + (data.result ? data.result.message : 'Falha'));
            btns.forEach(b => b.disabled = false);
        }
    });
}
